import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface WateringSchedule {
  day: string;
  action: string;
}

interface PlantData {
  plant: {
    name: string;
    nextWatering: string;
    soilMoisture: string;
    lastWatered: string;
  };
  wateringSchedule: WateringSchedule[];
}

export default function Widget() {
  const plantData = response.data as PlantData;
  const { plant, wateringSchedule } = plantData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFF', mb: 2 }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 0.5 }}>
              {plant.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Soil Moisture: {plant.soilMoisture}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Last Watered: {plant.lastWatered}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Next Watering: {plant.nextWatering}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={700} sx={{ mb: 1 }}>
              Watering Schedule
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {wateringSchedule.map((schedule, index) => (
                <Chip
                  key={index}
                  label={`${schedule.day}: ${schedule.action}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
